1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCH_THRESHOLD = 5;
5	const HIGH_ENCH_RATE = 0.3;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	const LOYALTY_THRESHOLD = 2;
9	const LOYALTY_RATE = 0.2;
10	const FOLLOWUP_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUES: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	const CAP_MULTIPLIER = 2;
31	const DEDUCTIBLE_PER_DAMAGE = 100;
32	
33	type Item = { type: string; cursed?: boolean; enchantment?: number };
34	
35	const COMPONENT_TYPES = ["rune", "moonstone"];
36	
37	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
38	
39	const sum = (values: number[]): number =>
40	  values.reduce((total, value) => total + value, 0);
41	
42	const sumOfBasePremiums = (items: Item[]): number =>
43	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
44	
45	const groupByType = (items: Item[]): Item[][] => {
46	  const groups: Record<string, Item[]> = {};
47	  for (const item of items) {
48	    if (!groups[item.type]) groups[item.type] = [];
49	    groups[item.type].push(item);
50	  }
51	  return Object.values(groups);
52	};
53	
54	const basePremiumForComponentGroup = (group: Item[]): number =>
55	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
56	
57	const basePremiumFor = (items: Item[]): number => {
58	  const components = items.filter(isComponent);
59	  const nonComponents = items.filter((item) => !isComponent(item));
60	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
61	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
62	};
63	
64	const surchargeFor = (
65	  items: Item[],
66	  rate: number,
67	  applies: (item: Item) => boolean,
68	): number =>
69	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
70	
71	const isCursed = (item: Item): boolean => item.cursed === true;
72	const isHighlyEnchanted = (item: Item): boolean =>
73	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
74	
75	const quotePremium = (items: Item[], yearsWithMHPCO: number, quoteIndex: number): number => {
76	  const base = basePremiumFor(items);
77	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
78	  const highEnchSurcharge = surchargeFor(items, HIGH_ENCH_RATE, isHighlyEnchanted);
79	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
80	  const followupDiscount = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
81	  return Math.ceil(base + curseSurcharge + highEnchSurcharge - loyaltyDiscount - followupDiscount + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
82	};
83	
84	type Policy = { items: Item[]; insuranceSum: number; remainingCap: number };
85	
86	const insuranceSumFor = (items: Item[]): number =>
87	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
88	
89	const handleClaim = (step: any, policies: Record<number, Policy>): { payout: number; remainingCap: number } => {
90	  const policy = policies[step.policy];
91	  const damages = step.incident.damages;
92	  const totalPayout = sum(
93	    damages.map((damage: { amount: number }) =>
94	      Math.max(0, Math.floor(damage.amount - DEDUCTIBLE_PER_DAMAGE))
95	    )
96	  );
97	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
98	  policy.remainingCap -= cappedPayout;
99	  return { payout: cappedPayout, remainingCap: policy.remainingCap };
100	};
101	
102	export const runScenario = (scenario: any): unknown => {
103	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
104	  let quoteIndex = 0;
105	  const policies: Record<number, Policy> = {};
106	  const results = scenario.steps.map((step: any, stepIndex: number) => {
107	    if (step.op === "claim") {
108	      return handleClaim(step, policies);
109	    }
110	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
111	    const insuranceSum = insuranceSumFor(step.items);
112	    policies[stepIndex] = {
113	      items: step.items,
114	      insuranceSum,
115	      remainingCap: insuranceSum * CAP_MULTIPLIER,
116	    };
117	    quoteIndex++;
118	    return { premium };
119	  });
120	  return { results };
121	};
